func TestNovelHistoryDepthBehavior(t *testing.T) {
	t.Run("served beyond UI cap and floor reached", func(t *testing.T) {
		// uiFloor = 2 years ago = 2024-06-01. Earliest receipt 2021-09 is older.
		// Widest two probes return the same earliest -> floor reached.
		probes := []depthProbe{
			{YearsBack: 2, StartDate: "2024-06-01", ReceiptCount: 5, EarliestReceipt: "2024-06-19"},
			{YearsBack: 5, StartDate: "2021-06-01", ReceiptCount: 20, EarliestReceipt: "2021-09-17"},
			{YearsBack: 8, StartDate: "2018-06-01", ReceiptCount: 20, EarliestReceipt: "2021-09-17"},
		}
		res := analyzeDepth(probes, "2024-06-01")
		if res.EarliestReceipt != "2021-09-17" {
			t.Fatalf("EarliestReceipt = %q, want 2021-09-17", res.EarliestReceipt)
		}
		if !res.ServedBeyondUICap {
			t.Fatal("expected ServedBeyondUICap = true")
		}
		if !res.FloorReached {
			t.Fatal("expected FloorReached = true (widest two probes agree)")
		}
	})

	t.Run("floor not reached when widest still surfaces older", func(t *testing.T) {
		probes := []depthProbe{
			{YearsBack: 2, EarliestReceipt: "2024-06-19"},
			{YearsBack: 5, EarliestReceipt: "2021-09-17"},
			{YearsBack: 8, EarliestReceipt: "2018-02-01"},
		}
		res := analyzeDepth(probes, "2024-06-01")
		if res.FloorReached {
			t.Fatal("expected FloorReached = false (each widening surfaced older)")
		}
	})

	t.Run("no receipts yields empty earliest and guidance note", func(t *testing.T) {
		res := analyzeDepth([]depthProbe{{YearsBack: 2}, {YearsBack: 5}}, "2024-06-01")
		if res.EarliestReceipt != "" || res.ServedBeyondUICap {
			t.Fatalf("empty history mishandled: %+v", res)
		}
		if res.Note == "" {
			t.Fatal("expected a guidance note for empty history")
		}
	})

	t.Run("ladder respects max and dogfood thinning", func(t *testing.T) {
		full := depthLadder(16, false)
		if len(full) == 0 || full[len(full)-1] != 16 {
			t.Fatalf("ladder cap not honored: %v", full)
		}
		dog := depthLadder(16, true)
		if len(dog) > 3 {
			t.Fatalf("dogfood ladder too long: %v", dog)
		}
	})
}
